\\u0440\\u0435\\u043b\\u0435\\u0432\\u0430\\u043d\\u0442\\u043d\\u043e\\u0441\\u0442\\u044c \\u0442\\u0435\\u043a\\u0441\\u0442\\u0430 \\u0438 \\u043b\\u043e\\u0433\\u0438\\u043a\\u0430 \\u0441\\u0442\\u0440\\u0443\\u043a\\u0442\\u0443\\u0440\\u044b \\u0432\\u043b\\u0438\\u044f\\u044e\\u0442 \\u043d\\u0430 \\u0432\\u043e\\u0441\\u043f\\u0440\\u0438\\u044f\\u0442\\u0438\\u0435 \\u043a\\u0430\\u0440\\u0442\\u043e\\u0447\\u043a\\u0438 \\u0438 \\u043f\\u043e\\u0432\\u0435\\u0434\\u0435\\u043d\\u0438\\u0435 \\u043f\\u043e\\u043a\\u0443\\u043f\\u0430\\u0442\\u0435\\u043b\\u044f. \\u041a\\u043e\\u0433\\u0434\\u0430 \\u0447\\u0435\\u043b\\u043e\\u0432\\u0435\\u043a \\u0432\\u0438\\u0434\\u0438\\u0442 \\u043f\\u043e\\u043d\\u044f\\u0442\\u043d\\u044b\\u0439 \\u0437\\u0430\\u0433\\u043e\\u043b\\u043e\\u0432\\u043e\\u043a \\u0438 \\u043f\\u043e\\u0441\\u043b\\u0435\\u0434\\u043e\\u0432\\u0430\\u0442\\u0435\\u043b\\u044c\\u043d\\u043e\\u0435 \\u043e\\u043f\\u0438\\u0441\\u0430\\u043d\\u0438\\u0435, \\u0434\\u043e\\u0432\\u0435\\u0440\\u0438\\u0435 \\u043a \\u0442\\u043e\\u0432\\u0430\\u0440\\u0443 \\u0440\\u0430\\u0441\\u0442\\u0435\\u0442. \\u0410 \\u0434\\u043e\\u0432\\u0435\\u0440\\u0438\\u0435 \\u043d\\u0430\\u043f\\u0440\\u044f\\u043c\\u0443\\u044e \\u0432\\u043b\\u0438\\u044f\\u0435\\u0442 \\u043d\\u0430 \\u043a\\u043b\\u0438\\u043a\\u0438, \\u0433\\u043b\\u0443\\u0431\\u0438\\u043d\\u0443 \\u043f\\u0440\\u043e\\u0441\\u043c\\u043e\\u0442\\u0440\\u0430 \\u0438 \\u0433\\u043e\\u0442\\u043e\\u0432\\u043d\\u043e\\u0441\\u0442\\u044c \\u043e\\u0444\\u043e\\u0440\\u043c\\u0438\\u0442\\u044c \\u0437\\u0430\\u043a\\u0430\\u0437.\\n\\nhuhjbu \\u043e\\u0442 jgvjuh \\u0445\\u043e\\u0440\\u043e\\u0448\\u043e \\u0432\\u043e\\u0441\\u043f\\u0440\\u0438\\u043d\\u0438\\u043c\\u0430\\u0435\\u0442\\u0441\\u044f \\u0432 \\u043a\\u0430\\u0442\\u0430\\u043b\\u043e\\u0433\\u0435 \\u0437\\u0430 \\u0441\\u0447\\u0435\\u0442 \\u043f\\u0440\\u043e\\u0441\\u0442\\u043e\\u0433\\u043e \\u0438 \\u0443\\u0432\\u0435\\u0440\\u0435\\u043d\\u043d\\u043e\\u0433\\u043e \\u043f\\u043e\\u0437\\u0438\\u0446\\u0438\\u043e\\u043d\\u0438\\u0440\\u043e\\u0432\\u0430\\u043d\\u0438\\u044f. \\u0422\\u0430\\u043a\\u043e\\u0439 \\u0442\\u043e\\u0432\\u0430\\u0440 \\u0443\\u0434\\u043e\\u0431\\u043d\\u043e \\u043f\\u0440\\u043e\\u0441\\u043c\\u0430\\u0442\\u0440\\u0438\\u0432\\u0430\\u0442\\u044c \\u043a\\u0430\\u043a \\u0441 \\u043a\\u043e\\u043c\\u043f\\u044c\\u044e\\u0442\\u0435\\u0440\\u0430, \\u0442\\u0430\\u043a \\u0438 \\u0441\\u043e \\u0441\\u043c\\u0430\\u0440\\u0442\\u0444\\u043e\\u043d\\u0430: \\u043a\\u043b\\u044e\\u0447\\u0435\\u0432\\u044b\\u0435 \\u0441\\u043b\\u043e\\u0432\\u0430 \\u043d\\u0430\\u0445\\u043e\\u0434\\u044f\\u0442\\u0441\\u044f \\u043d\\u0430 \\u0441\\u0432\\u043e\\u0438\\u0445 \\u043c\\u0435\\u0441\\u0442\\u0430\\u0445, \\u0431\\u0440\\u0435\\u043d\\u0434 \\u0432\\u044b\\u0434\\u0435\\u043b\\u0435\\u043d, \\u043a\\u0430\\u0442\\u0435\\u0433\\u043e\\u0440\\u0438\\u044f \\u043f\\u043e\\u043d\\u044f\\u0442\\u043d\\u0430. \\u042d\\u0442\\u043e \\u0432\\u0430\\u0436\\u043d\\u043e \\u0434\\u043b\\u044f \\u0441\\u043e\\u0432\\u0440\\u0435\\u043c\\u0435\\u043d\\u043d\\u043e\\u0433\\u043e \\u043f\\u043e\\u043a\\u0443\\u043f\\u0430\\u0442\\u0435\\u043b\\u044f, \\u043a\\u043e\\u0442\\u043e\\u0440\\u044b\\u0439 \\u043f\\u0440\\u0438\\u043d\\u0438\\u043c\\u0430\\u0435\\u0442 \\u0440\\u0435\\u0448\\u0435\\u043d\\u0438\\u0435 \\u0431\\u044b\\u0441\\u0442\\u0440\\u043e. \\u0415\\u043c\\u0443 \\u043d\\u0435 \\u043d\\u0443\\u0436\\u0435\\u043d \\u0434\\u043b\\u0438\\u043d\\u043d\\u044b\\u0439 \\u0441\\u043f\\u0438\\u0441\\u043e\\u043a \\u0430\\u0431\\u0441\\u0442\\u0440\\u0430\\u043a\\u0442\\u043d\\u044b\\u0445 \\u043e\\u0431\\u0435\\u0449\\u0430\\u043d\\u0438\\u0439 \\u2014 \\u0435\\u043c\\u0443 \\u043d\\u0443\\u0436\\u043d\\u0430 \\u0442\\u043e\\u0447\\u043d\\u043e\\u0441\\u0442\\u044c, \\u044f\\u0441\\u043d\\u043e\\u0441\\u0442\\u044c \\u0438 \\u043e\\u0449\\u0443\\u0449\\u0435\\u043d\\u0438\\u0435, \\u0447\\u0442\\u043e \\u043a\\u0430\\u0440\\u0442\\u043e\\u0447\\u043a\\u0430 \\u0441\\u0434\\u0435\\u043b\\u0430\\u043d\\u0430 \\u043f\\u0440\\u043e\\u0444\\u0435\\u0441\\u0441\\u0438\\u043e\\u043d\\u0430\\u043b\\u044c\\u043d\\u043e. \\u0418\\u043c\\u0435\\u043d\\u043d\\u043e \\u0442\\u0430\\u043a\\u0430\\u044f \\u043f\\u043e\\u0434\\u0430\\u0447\\u0430 \\u043f\\u043e\\u043c\\u043e\\u0433\\u0430\\u0435\\u0442 \\u0442\\u043e\\u0432\\u0430\\u0440\\u0443 \\u043d\\u0435 \\u0442\\u0435\\u0440\\u044f\\u0442\\u044c\\u0441\\u044f \\u0441\\u0440\\u0435\\u0434\\u0438 \\u043c\\u043d\\u043e\\u0436\\u0435\\u0441\\u0442\\u0432\\u0430 \\u0430\\u043d\\u0430\\u043b\\u043e\\u0433\\u0438\\u0447\\u043d\\u044b\\u0445 \\u043f\\u0440\\u0435\\u0434\\u043b\\u043e\\u0436\\u0435\\u043d\\u0438\\u0439.\\n\\n\\u041f\\u043e\\u043a\\u0443\\u043f\\u0430\\u044f huhjbu \\u0431\\u0440\\u0435\\u043d\\u0434\\u0430 jgvjuh, \\u043a\\u043b\\u0438\\u0435\\u043d\\u0442 \\u043f\\u043e\\u043b\\u0443\\u0447\\u0430\\u0435\\u0442 \\u043d\\u0435 \\u043f\\u0440\\u043e\\u0441\\u0442\\u043e \\u043f\\u043e\\u0437\\u0438\\u0446\\u0438\\u044e \\u0438\\u0437 \\u043a\\u0430\\u0442\\u0435\\u0433\\u043e\\u0440\\u0438\\u0438 ibyhjbhbh, \\u0430 \\u043f\\u043e\\u043d\\u044f\\u0442\\u043d\\u044b\\u0439 \\u0432\\u044b\\u0431\\u043e\\u0440 \\u0431\\u0435\\u0437 \\u043b\\u0438\\u0448\\u043d\\u0435\\u0439 \\u043f\\u0443\\u0442\\u0430\\u043d\\u0438\\u0446\\u044b. \\u041e\\u043d \\u0432\\u0438\\u0434\\u0438\\u0442 \\u043a\\u043e\\u043d\\u043a\\u0440\\u0435\\u0442\\u043d\\u043e\\u0435 \\u043d\\u0430\\u0437\\u0432\\u0430\\u043d\\u0438\\u0435, \\u0437\\u043d\\u0430\\u043a\\u043e\\u043c\\u0438\\u0442\\u0441\\u044f \\u0441 \\u0431\\u0440\\u0435\\u043d\\u0434\\u043e\\u043c, \\u0431\\u044b\\u0441\\u0442\\u0440\\u043e \\u043d\\u0430\\u0445\\u043e\\u0434\\u0438\\u0442 \\u043d\\u0443\\u0436\\u043d\\u0443\\u044e \\u043a\\u0430\\u0442\\u0435\\u0433\\u043e\\u0440\\u0438\\u044e \\u0438 \\u043c\\u043e\\u0436\